{% set status_mode = frappe.form_dict.get('status_mode') or 'released_only' %}
{% set category_raw = frappe.form_dict.get('option_category') or '' %}
{% set group_raw = frappe.form_dict.get('option_group') or '' %}
{% set default_only = (frappe.form_dict.get('default_only') or '0') in ['1', 'true', 'True', 'yes', 'on'] %}
{% set include_builder = (frappe.form_dict.get('include_builder') or '0') in ['1', 'true', 'True', 'yes', 'on'] %}

{% if status_mode == 'released_only' %}
  {% set allowed_statuses = ['Released'] %}
  {% set include_inactive = False %}
  {% set status_label = 'Released only' %}
{% elif status_mode == 'draft_only' %}
  {% set allowed_statuses = ['Draft'] %}
  {% set include_inactive = False %}
  {% set status_label = 'Draft only' %}
{% elif status_mode == 'all_active' %}
  {% set allowed_statuses = ['Draft', 'Released'] %}
  {% set include_inactive = False %}
  {% set status_label = 'All active options' %}
{% elif status_mode == 'all_including_inactive' %}
  {% set allowed_statuses = ['Draft', 'Released', 'Deprecated'] %}
  {% set include_inactive = True %}
  {% set status_label = 'All options, including inactive' %}
{% else %}
  {% set allowed_statuses = ['Released'] %}
  {% set include_inactive = False %}
  {% set status_label = 'Released only' %}
{% endif %}

{% set category_filters = [] %}
{% for c in category_raw.split(',') %}
  {% if c | trim %}
    {% set _ = category_filters.append(c | trim) %}
  {% endif %}
{% endfor %}

{% set group_filters = [] %}
{% for g in group_raw.split(',') %}
  {% if g | trim %}
    {% set _ = group_filters.append(g | trim) %}
  {% endif %}
{% endfor %}

{% set all_options = frappe.get_all(
    'InductOne Configuration Option',
    fields=[
      'name',
      'option_code',
      'option_name',
      'option_category',
      'option_group',
      'option_group_required',
      'is_default_selection',
      'is_active',
      'status',
      'mapping_status',
      'builder_description',
      'internal_notes',
      'sort_order'
    ],
    order_by='option_category asc, sort_order asc, option_code asc'
) %}

{% set filtered_options = [] %}

{% for o in all_options %}
  {% set active_ok = include_inactive or ((o.is_active or 0) | int == 1) %}
  {% set status_ok = (allowed_statuses | length == 0) or (o.status in allowed_statuses) %}
  {% set category_ok = (category_filters | length == 0) or (o.option_category in category_filters) %}
  {% set group_ok = (group_filters | length == 0) or (o.option_group in group_filters) %}
  {% set default_ok = (not default_only) or ((o.is_default_selection or 0) | int == 1) %}

  {% if active_ok and status_ok and category_ok and group_ok and default_ok %}
    {% set _ = filtered_options.append(o) %}
  {% endif %}
{% endfor %}

{% set categories = [] %}

{% for o in filtered_options %}
  {% if o.option_category not in categories %}
    {% set _ = categories.append(o.option_category) %}
  {% endif %}
{% endfor %}

{% set total_count = filtered_options | length %}
{% set released_count = filtered_options | selectattr('status', 'equalto', 'Released') | list | length %}
{% set draft_count = filtered_options | selectattr('status', 'equalto', 'Draft') | list | length %}

{% set filter_summary = [] %}
{% set _ = filter_summary.append('Status: ' ~ status_label) %}

{% if category_filters | length %}
  {% set _ = filter_summary.append('Category: ' ~ (category_filters | join(', '))) %}
{% endif %}

{% if group_filters | length %}
  {% set _ = filter_summary.append('Group: ' ~ (group_filters | join(', '))) %}
{% endif %}

{% if default_only %}
  {% set _ = filter_summary.append('Default selections only') %}
{% endif %}

<div class="catalog-header">
  <div class="catalog-title">InductOne Configuration Options Catalog</div>

  {% if include_builder %}
    <div class="catalog-subtitle">Comprehensive Internal Version — Sales + Engineering Descriptions</div>
  {% else %}
    <div class="catalog-subtitle">Sales-Facing Version — Available Released Options</div>
  {% endif %}

  <div class="catalog-meta">
    Generated {{ frappe.utils.now_datetime().strftime('%B %d, %Y') }}
    &nbsp;|&nbsp; {{ filter_summary | join(' | ') }}
    {% if include_builder %}
      &nbsp;|&nbsp; Confidential Internal Use
    {% else %}
      &nbsp;|&nbsp; Confidential
    {% endif %}
  </div>
</div>

<div class="summary-bar">
  <div class="summary-item">
    <span class="summary-label">Filtered Options</span>
    <span class="summary-value">{{ total_count }}</span>
  </div>

  <div class="summary-item">
    <span class="summary-label">Released</span>
    <span class="summary-value">{{ released_count }}</span>
  </div>

  <div class="summary-item">
    <span class="summary-label">Draft</span>
    <span class="summary-value">{{ draft_count }}</span>
  </div>

  <div class="summary-item">
    <span class="summary-label">Categories</span>
    <span class="summary-value">{{ categories | length }}</span>
  </div>
</div>

{% for category in categories | sort %}
{% set cat_options = filtered_options | selectattr('option_category', 'equalto', category) | list %}

{% if cat_options %}
<div class="category-block">

  {% for o in cat_options %}
    {% if loop.first %}
    <div class="category-start-keep">
      <div class="category-heading">{{ category or 'Uncategorized' }} &nbsp;({{ cat_options | length }})</div>
    {% endif %}

    <div class="option-card">
      <div class="option-card-header">
        <span class="option-code">{{ o.option_code or '—' }}</span>

        <span class="option-name">
          {{ o.option_name or '—' }}

          {% if o.option_group %}
            <span class="option-group-tag">{{ o.option_group }}</span>
          {% endif %}
        </span>

        <span class="option-status {% if o.status == 'Released' %}released{% elif o.status == 'Draft' %}draft{% endif %}">
          {{ o.status or '' }}
        </span>
      </div>

      {% set sales_desc = o.internal_notes or '' %}
      {% set builder_desc = o.builder_description or '' %}

      {% if sales_desc %}
      <div class="description-block sales-description">
        <div class="description-label">Sales Description</div>
        <div class="option-description">
          {{ sales_desc | trim | replace('\n', '<br>') }}
        </div>
      </div>
      {% endif %}

      {% if include_builder and builder_desc %}
        {% set _eff = builder_desc.split('Configuration effect:') %}

        <div class="description-block builder-description">
          <div class="description-label">Engineering / Builder Description</div>

          <div class="builder-main-description">
            {{ _eff[0] | trim | replace('\n', '<br>') }}
          </div>

          {% if _eff | length > 1 %}
            {% set _notes = _eff[1].split('Notes:') %}

            <div class="builder-subsection configuration-effect">
              <div class="builder-subsection-label">Configuration Effect</div>
              <div class="builder-subsection-body">
                {{ _notes[0] | trim | replace('\n', '<br>') }}
              </div>
            </div>

            {% if _notes | length > 1 %}
            <div class="builder-subsection builder-notes">
              <div class="builder-subsection-label">Notes</div>
              <div class="builder-subsection-body">
                {{ _notes[1] | trim | replace('\n', '<br>') }}
              </div>
            </div>
            {% endif %}
          {% endif %}
        </div>
      {% endif %}

      {% if not sales_desc and (not include_builder or not builder_desc) %}
      <div class="option-description-empty">No description available.</div>
      {% endif %}
    </div>

    {% if loop.first %}
    </div>
    {% endif %}
  {% endfor %}

</div>
{% endif %}
{% endfor %}

{% if total_count == 0 %}
<p class="no-options">
  No options matched the selected catalog filters:
  {{ filter_summary | join(' | ') }}
</p>
{% endif %}

<div class="footer-block">
  <span>Plus One Robotics — Confidential and Proprietary</span>

  {% if include_builder %}
    <span>InductOne Options Catalog, Comprehensive Internal Version &nbsp;|&nbsp; {{ frappe.utils.now_datetime().strftime('%Y-%m-%d') }}</span>
  {% else %}
    <span>InductOne Options Catalog &nbsp;|&nbsp; {{ frappe.utils.now_datetime().strftime('%Y-%m-%d') }}</span>
  {% endif %}
</div>

css:
.catalog-header {
  border-bottom: 2px solid #111;
  padding-bottom: 12px;
  margin-bottom: 14px;
}

.catalog-title {
  font-size: 22px;
  font-weight: 700;
  color: #111;
}

