  font-size: 13px;
  margin-top: 4px;
  color: #444;
}

.catalog-meta {
  font-size: 10px;
  margin-top: 6px;
  color: #666;
}

.summary-bar {
  display: table;
  width: 100%;
  border: 1px solid #d9d9d9;
  margin-bottom: 18px;
}

.summary-item {
  display: table-cell;
  width: 25%;
  padding: 8px 10px;
  border-right: 1px solid #d9d9d9;
  vertical-align: middle;
}

.summary-item:last-child {
  border-right: none;
}

.summary-label {
  display: block;
  font-size: 9px;
  text-transform: uppercase;
  color: #666;
  letter-spacing: 0.5px;
}

.summary-value {
  display: block;
  font-size: 15px;
  font-weight: 700;
  color: #111;
  margin-top: 2px;
}

.category-block {
  margin-bottom: 20px;
}

.category-start-keep {
  page-break-inside: avoid;
  break-inside: avoid;
}

.category-heading {
  background: #111;
  color: #fff;
  padding: 7px 10px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: uppercase;
  border-radius: 3px;
  margin-bottom: 8px;
  page-break-after: avoid;
  break-after: avoid;
}

.option-card {
  border: 1px solid #d6d6d6;
  border-radius: 4px;
  margin-bottom: 10px;
  page-break-inside: avoid;
  break-inside: avoid;
  overflow: hidden;
}

.option-card-header {
  background: #f2f2f2;
  border-bottom: 1px solid #d6d6d6;
  padding: 8px 10px;
  font-size: 10px;
}

.option-code {
  font-weight: 700;
  color: #111;
  margin-right: 8px;
}

.option-name {
  font-weight: 600;
  color: #222;
}

.option-group-tag {
  font-size: 8px;
  color: #2f45d8;
  margin-left: 8px;
  text-transform: uppercase;
}

.option-status {
  float: right;
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
}

.option-status.released {
  color: #1f7a35;
}

.option-status.draft {
  color: #a36b00;
}

.description-block {
  padding: 9px 12px;
  border-bottom: 1px solid #ededed;
}

.description-block:last-child {
  border-bottom: none;
}

.description-label {
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.7px;
  margin-bottom: 5px;
}

.sales-description {
  background: #fbfdff;
}

.sales-description .description-label {
  color: #005eb8;
}

.builder-description {
  background: #fffaf2;
}

.builder-description .description-label {
  color: #6b3f00;
}

.option-description {
  font-size: 10px;
  line-height: 1.45;
  color: #111;
}

.builder-main-description {
  font-size: 10px;
  line-height: 1.55;
  color: #344054;
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid #f2f4f7;
}

.builder-subsection {
  margin-top: 10px;
}

.builder-subsection-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #1794CE;
  margin-bottom: 5px;
}

.builder-subsection-body {
  font-size: 10px;
  color: #475467;
  line-height: 1.6;
  padding-left: 12px;
  border-left: 2px solid #1794CE;
}

.builder-notes .builder-subsection-body {
  border-left-color: #D0D5DD;
}

.option-description-empty {
  padding: 10px 12px;
  font-size: 10px;
  color: #999;
  font-style: italic;
}

.no-options {
  font-size: 12px;
  color: #777;
  padding: 12px;
  background: #f9fafb;
  border: 1px solid #eaecf0;
  border-radius: 4px;
}

.footer-block {
  margin-top: 24px;
  border-top: 1px solid #ccc;
  padding-top: 8px;
  font-size: 9px;
  color: #666;
  display: flex;
  justify-content: space-between;
}

@media print {
  .category-heading,
  .option-card-header,
  .sales-description,
  .builder-description {
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }
}

