  padding: 9px 12px;
  border-bottom: 1px solid #ededed;
}

.description-block:last-child {
  border-bottom: none;
}

.description-label {
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.7px;
  margin-bottom: 5px;
}

.sales-description {
  background: #fbfdff;
}

.sales-description .description-label {
  color: #005eb8;
}

.builder-description {
  background: #fffaf2;
}

.builder-description .description-label {
  color: #6b3f00;
}

.option-description {
  font-size: 10px;
  line-height: 1.45;
  color: #111;
}

.builder-main-description {
  font-size: 10px;
  line-height: 1.55;
  color: #344054;
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid #f2f4f7;
}

.builder-subsection {
  margin-top: 10px;
}

.builder-subsection-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #1794CE;
  margin-bottom: 5px;
}

.builder-subsection-body {
  font-size: 10px;
  color: #475467;
  line-height: 1.6;
  padding-left: 12px;
  border-left: 2px solid #1794CE;
}

.builder-notes .builder-subsection-body {
  border-left-color: #D0D5DD;
}

.option-description-empty {
  padding: 10px 12px;
  font-size: 10px;
